(()=>{'use strict';
const DESIGN_W=980;
function ensureMeta(){let m=document.querySelector('meta[name="viewport"]');if(!m){m=document.createElement('meta');m.name='viewport';document.head.appendChild(m)}m.content=`width=${DESIGN_W},initial-scale=1,viewport-fit=cover`}
function ensureStyle(){let st=document.getElementById('layout-lock-v258');if(!st){st=document.createElement('style');st.id='layout-lock-v258';st.textContent=`html,body{margin:0!important;padding:0!important;min-width:${DESIGN_W}px!important;width:${DESIGN_W}px!important;max-width:none!important;overflow-x:auto!important;background:#f6f7f8!important;touch-action:pan-x pan-y pinch-zoom!important}.topbar{width:${DESIGN_W}px!important;max-width:none!important;margin:0!important;height:56px!important;padding:0 16px!important}.wrap{width:${DESIGN_W}px!important;max-width:none!important;margin:0!important;padding:16px!important}.topGrid{display:grid!important;grid-template-columns:1.1fr .9fr!important;gap:14px!important}.tabs{display:grid!important;grid-template-columns:repeat(5,1fr)!important;gap:10px!important}.filterGrid{display:grid!important;grid-template-columns:1fr 1fr 1fr!important;gap:12px!important}.range{display:grid!important;grid-template-columns:1fr 24px 1fr!important;gap:6px!important}.dash{display:block!important}.searchLine{display:grid!important;grid-template-columns:1fr 360px!important;gap:10px!important}.summaryHead{display:flex!important;align-items:center!important;justify-content:space-between!important}.actions{display:flex!important;gap:8px!important;margin-top:0!important;grid-template-columns:none!important}.summary{display:grid!important;grid-template-columns:repeat(4,1fr)!important;gap:10px!important}.bottomBar{display:flex!important;justify-content:space-between!important}.leftBtns{display:flex!important;gap:8px!important}.tableWrap{overflow:auto!important;-webkit-overflow-scrolling:touch!important}.tbl{min-width:940px!important;font-size:13px!important}.help{display:inline-flex!important;align-items:center!important}.prepBtn{height:34px;border:1px solid #15803d;background:#087b34;color:#fff;border-radius:8px;font-weight:950;padding:0 10px;white-space:nowrap}.store-guide{margin:0 0 10px;padding:10px 12px;border:1px solid #bbf7d0;background:#f0fdf4;color:#14532d;border-radius:10px;font-weight:900;font-size:13px}.store-guide b{color:#065f27}.store-guide small{display:block;color:#166534;font-weight:700;margin-top:2px}@media(max-width:99999px){.topGrid{grid-template-columns:1.1fr .9fr!important}.tabs{grid-template-columns:repeat(5,1fr)!important}.filterGrid{grid-template-columns:1fr 1fr 1fr!important}.summary{grid-template-columns:repeat(4,1fr)!important}.searchLine{grid-template-columns:1fr 360px!important}.bottomBar{display:flex!important}.leftBtns{display:flex!important}.actions{display:flex!important}}@media print{html,body{width:auto!important;min-width:0!important;overflow:visible!important}.topbar,.wrap{width:auto!important}}`;document.head.appendChild(st)}else if(document.head.lastElementChild!==st){document.head.appendChild(st)}return st}
function labels(){const t=document.querySelector('.title');if(t)t.textContent='Solomon DOIT Pro V2.5.8';document.title='Solomon DOIT Pro V2.5.8';const labs=[...document.querySelectorAll('.field label')];labs.forEach(l=>{if(l.textContent.includes('ร้านค้า')||l.textContent.includes('ร้านที่คีย์'))l.textContent='เลือกร้านที่จะใส่จำนวนสินค้า'});const h=document.querySelector('.mobileHint');if(h&&h.textContent.includes('ร้านที่คีย์'))h.textContent='เลือก PS และเลือกร้านที่จะใส่จำนวนสินค้า จากนั้นกรอกจำนวนส่งจริง / ใส่เพิ่ม / ดึงออก ในตารางด้านล่าง'}
function addPrepButton(){const a=document.querySelector('.actions');if(a&&!document.getElementById('prepPrint')){const b=document.createElement('button');b.id='prepPrint';b.className='prepBtn';b.textContent='เตรียมปริ้น';a.prepend(b)}}
function addStoreGuide(){const filters=document.querySelector('.filters');if(filters&&!document.querySelector('.store-guide')){const g=document.createElement('div');g.className='store-guide';g.innerHTML='<b>เลือกร้านตรงช่อง “เลือกร้านที่จะใส่จำนวนสินค้า”</b><small>อยู่ในตัวกรองข้อมูล แถวเดียวกับช่อง PS แล้วค่อยกรอกจำนวนในตาราง</small>';filters.insertBefore(g,filters.querySelector('.filterGrid'))}}
function tick(){ensureMeta();ensureStyle();labels();addPrepButton();addStoreGuide();document.body.style.transform='';document.documentElement.style.transform=''}
window.addEventListener('resize',tick);window.visualViewport&&window.visualViewport.addEventListener('resize',tick);document.addEventListener('DOMContentLoaded',()=>{tick();setTimeout(tick,150);setTimeout(tick,800);new MutationObserver(()=>setTimeout(tick,0)).observe(document.documentElement,{childList:true,subtree:true});});
})();
